import unittest

class TestSolution(unittest.TestCase):
    def test_basic_overlap(self):
        result = common_friends(["Alice", "Bob", "Charlie"], ["Bob", "Diana", "Charlie"])
        self.assertEqual(result, ["Bob", "Charlie"])

    def test_no_overlap(self):
        result = common_friends(["Alice", "Bob"], ["Charlie", "Diana"])
        self.assertEqual(result, [])

    def test_complete_overlap(self):
        result = common_friends(["Alice", "Bob", "Charlie"], ["Alice", "Bob", "Charlie"])
        self.assertEqual(result, ["Alice", "Bob", "Charlie"])

    def test_hidden_both_empty(self):
        result = common_friends([], [])
        self.assertEqual(result, [])

    def test_hidden_one_empty(self):
        result = common_friends(["Alice"], [])
        self.assertEqual(result, [])

    def test_hidden_duplicates_in_input(self):
        result = common_friends(["Alice", "Alice", "Bob"], ["Alice", "Bob"])
        self.assertEqual(result, ["Alice", "Bob"])

    def test_hidden_single_common(self):
        result = common_friends(["Zara"], ["Zara"])
        self.assertEqual(result, ["Zara"])

    def test_hidden_larger_lists(self):
        result = common_friends(
            ["Alice", "Bob", "Eve", "Frank", "Grace"],
            ["Bob", "Charlie", "Diana", "Eve", "Grace"]
        )
        self.assertEqual(result, ["Bob", "Eve", "Grace"])

    def test_hidden_case_sensitive(self):
        result = common_friends(["alice", "Bob"], ["Alice", "Bob"])
        self.assertEqual(result, ["Bob"])

    def test_hidden_sorted_output(self):
        result = common_friends(["Zara", "Alice", "Mia"], ["Mia", "Zara", "Alice"])
        self.assertEqual(result, ["Alice", "Mia", "Zara"])

if __name__ == '__main__':
    unittest.main()
